  /**
   * 同步原生正则引擎状态：清除缓存并刷新原生正则UI面板
   */
  async function syncNativeRegexState() {
    try {
      const engine = await import("../../regex/engine.js");
      // 清除正则引擎缓存，确保下次执行时使用最新数据
      engine.RegexProvider.instance.clear();
      // 就地更新原生正则UI面板（保留原生事件绑定）
      const containers = [
        {
          sel: "#saved_regex_scripts",
          type: engine.SCRIPT_TYPES.GLOBAL,
        },
        {
          sel: "#saved_scoped_scripts",
          type: engine.SCRIPT_TYPES.SCOPED,
        },
        {
          sel: "#saved_preset_scripts",
          type: engine.SCRIPT_TYPES.PRESET,
        },
      ];
      let hasMissingRows = false;
      for (const { sel, type } of containers) {
        const container = $(sel);
        if (!container.length) continue;
        const scripts = engine.getScriptsByType(type);
        const scriptIds = new Set(scripts.map((s) => s.id));
        // 移除已删除的脚本行
        container.children().each(function () {
          const id = $(this).attr("id");
          if (id && !scriptIds.has(id)) $(this).remove();
        });
        // 检查是否有新脚本缺少原生行
        for (const script of scripts) {
          if (!script.id) continue;
          const row = container.children("#" + $.escapeSelector(script.id));
          if (row.length) {
            // 更新名称
            row
              .find(".regex_script_name")
              .text(script.scriptName)
              .attr("title", script.scriptName);
            // 更新禁用状态
            row
              .find(".disable_regex")
              .prop("checked", script.disabled ?? false);
            // 移动到容器末尾以保持正确顺序
            container.append(row);
          } else {
            // 标记有缺失行，需要完整重建
            hasMissingRows = true;
          }
        }
      }
      // 如果有新脚本缺少原生行，完整重建面板
      if (hasMissingRows) {
        console.debug(
          "[CFM] syncNativeRegexState: detected missing rows, rebuilding panels",
        );
        try {
          // 尝试获取原生模板
          let scriptTemplate;
          try {
            const { renderExtensionTemplateAsync } =
              await import("../../extensions.js");
            scriptTemplate = $(
              await renderExtensionTemplateAsync("regex", "scriptTemplate"),
            );
          } catch (templateErr) {
            console.debug(
              "[CFM] syncNativeRegexState: template load failed, using fallback",
              templateErr,
            );
          }
          // 如果模板加载失败或为空，使用内联回退模板
          if (!scriptTemplate || !scriptTemplate.length) {
            scriptTemplate = $(`
              <div class="regex-script-label flex-container flexnowrap">
                <input type="checkbox" class="regex_bulk_checkbox" />
                <span class="drag-handle menu-handle">&#9776;</span>
                <div class="regex_script_name flex1 overflow-hidden"></div>
                <div class="flex-container flexnowrap">
                  <label class="checkbox flex-container margin-r5" for="regex_disable">
                    <input type="checkbox" name="regex_disable" class="disable_regex" />
                    <span class="regex-toggle-on fa-solid fa-toggle-on" title="Disable script"></span>
                    <span class="regex-toggle-off fa-solid fa-toggle-off" title="Enable script"></span>
                  </label>
                  <div class="edit_existing_regex menu_button" title="Edit script">
                    <i class="fa-solid fa-pencil"></i>
                  </div>
                  <div class="export_regex menu_button" title="Export script">
                    <i class="fa-solid fa-file-export"></i>
                  </div>
                  <div class="delete_regex menu_button" title="Delete script">
                    <i class="fa-solid fa-trash"></i>
                  </div>
                </div>
              </div>
            `);
          }
          for (const { sel, type } of containers) {
            const container = $(sel);
            if (!container.length) continue;
            const scripts = engine.getScriptsByType(type);
            // 清空容器后完整重建
            container.empty();
            scripts.forEach((script, index) => {
              if (!script.id) {
                script.id = getContext().uuidv4();
              }
              const scriptHtml = scriptTemplate.clone();
              const saveFunc = async () => {
                await engine.saveScriptsByType(
                  engine.getScriptsByType(type),
                  type,
                );
              };
              scriptHtml.attr("id", script.id);
              scriptHtml
                .find(".regex_script_name")
                .text(script.scriptName)
                .attr("title", script.scriptName);
              scriptHtml
                .find(".disable_regex")
                .prop("checked", script.disabled ?? false)
                .on("input", async function () {
                  script.disabled = !!$(this).prop("checked");
                  await saveFunc();
                });
              scriptHtml.find(".regex-toggle-on").on("click", function () {
                scriptHtml
                  .find(".disable_regex")
                  .prop("checked", true)
                  .trigger("input");
              });
              scriptHtml.find(".regex-toggle-off").on("click", function () {
                scriptHtml
                  .find(".disable_regex")
                  .prop("checked", false)
                  .trigger("input");
              });
              scriptHtml.find(".edit_existing_regex").on("click", function () {
                // 触发原生编辑对话框
                const id = scriptHtml.attr("id");
                const editBtn = $("#" + $.escapeSelector(String(id))).find(
                  ".edit_existing_regex",
                );
                if (editBtn.length && editBtn[0] !== this) {
                  editBtn.trigger("click");
                }
              });
              scriptHtml.find(".export_regex").on("click", function () {
                const fileName = `regex-${(script.scriptName || "").replace(/[\s.<>:"/\\|?*\x00-\x1F\x7F]/g, "_").toLowerCase()}.json`;
                const fileData = JSON.stringify(script, null, 4);
                const blob = new Blob([fileData], {
                  type: "application/json",
                });
                const url = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = url;
                a.download = fileName;
                a.click();
                URL.revokeObjectURL(url);
              });
              scriptHtml.find(".delete_regex").on("click", async function () {
                // 删除操作交由原生处理
                const nativeRow = $("#" + $.escapeSelector(String(script.id)));
                if (nativeRow.length) {
                  nativeRow.find(".delete_regex").trigger("click");
                }
              });
              container.append(scriptHtml);
            });
          }
          console.debug(
            "[CFM] syncNativeRegexState: rebuilt native regex panels",
          );
        } catch (rebuildErr) {
          console.error(
            "[CFM] syncNativeRegexState rebuild failed:",
            rebuildErr,
          );
        }
      }
    } catch (e) {
      // 静默失败：原生正则UI可能未加载
      console.debug("[CFM] syncNativeRegexState:", e);
    }
  }

  /**
   * 保存角色正则脚本到服务器
   * @param {string} avatar - 角色的 avatar
   * @param {Array} scripts - 正则脚本列表
   */
  async function saveCharRegexScripts(avatar, scripts) {
    // 1. 同步更新内存中的角色数据（直接修改 characters 数组引用，与原生 writeExtensionField 保持一致）
    const chars = getCharacters();
    const ch = chars.find((c) => c.avatar === avatar);
    if (ch) {
      if (!ch.data) ch.data = {};
      if (!ch.data.extensions) ch.data.extensions = {};
      ch.data.extensions.regex_scripts = scripts;
      // 同步更新 json_data（与原生 writeExtensionField 行为一致，防止后续保存时数据不同步）
      if (ch.json_data) {
        try {
          const jsonData = JSON.parse(ch.json_data);
          if (!jsonData.data) jsonData.data = {};
          if (!jsonData.data.extensions) jsonData.data.extensions = {};
          jsonData.data.extensions.regex_scripts = scripts;
          ch.json_data = JSON.stringify(jsonData);
        } catch (parseErr) {
          console.debug("[CFM] json_data 同步失败:", parseErr);
        }
      }
    }
    // 2. 持久化到服务器
    const ctx = getContext();
    const headers = ctx.getRequestHeaders();
    await fetch("/api/characters/merge-attributes", {
      method: "POST",
      headers: headers,
      body: JSON.stringify({
        avatar: avatar,
        data: { extensions: { regex_scripts: scripts } },
      }),
    });
    // 3. 清除原生正则引擎缓存 & 刷新原生正则UI
    // 注意：不再调用 ctx.getCharacters()，因为：
    //  - 我们已经直接更新了 characters 数组中的角色对象
    //  - getCharacters() 会触发 selectCharacterById → 异步重建原生正则面板，
    //    导致与 syncNativeRegexState 的同步结果产生时序冲突
    await syncNativeRegexState();
  }

  /**
   * 渲染角色的正则脚本子列表
   * @param {jQuery} charRow - 角色卡行的 jQuery 对象
   * @param {string} avatar - 角色的 avatar
   * @param {Array} scripts - 正则脚本列表
   * @param {string} charName - 角色名称
   * @param {boolean} [isTarget=true] - 是否为当前目标角色（只有目标角色可激活/取消激活正则）
   */
  function renderCharRegexSubList(
    charRow,
    avatar,
    scripts,
    charName,
    isTarget = true,
  ) {
    charRow.next(".cfm-regex-sublist").remove();
    const subList = $('<div class="cfm-regex-sublist"></div>');

    // === 工具栏（仅对目标角色显示） ===
    if (isTarget) {
      const regexToolbar = $(`
        <div class="cfm-regex-toolbar">
          <button class="cfm-btn cfm-btn-sm cfm-regex-import-btn" title="导入正则脚本"><i class="fa-solid fa-file-import"></i> 导入</button>
          <input type="file" class="cfm-regex-import-file" multiple accept=".json" style="display:none;">
          <button class="cfm-btn cfm-btn-sm cfm-regex-create-btn" title="新增正则脚本"><i class="fa-solid fa-plus"></i> 新增</button>
          <button class="cfm-btn cfm-btn-sm cfm-regex-batch-toggle ${cfmRegexBatchMode ? "cfm-regex-batch-active" : ""}" title="批量操作模式"><i class="fa-solid fa-list-check"></i> ${cfmRegexBatchMode ? "退出批量" : "批量操作"}</button>
          <span class="cfm-regex-count">${scripts ? scripts.length : 0} 个脚本</span>
        </div>
      `);
      // 导入按钮
      regexToolbar.find(".cfm-regex-import-btn").on("click", (e) => {
        e.stopPropagation();
        regexToolbar.find(".cfm-regex-import-file").val("").trigger("click");
      });
      regexToolbar.find(".cfm-regex-import-file").on("change", async (e) => {
        e.stopPropagation();
        const files = e.target.files;
        if (!files || files.length === 0) return;
        try {
          for (const file of files) {
            const text = await file.text();
            const parsed = JSON.parse(text);
            const toImport = Array.isArray(parsed) ? parsed : [parsed];
            for (const regexScript of toImport) {
              if (!regexScript.scriptName) {
                cfmToastr.warning("跳过无名称的正则脚本");
                continue;
              }
              regexScript.id = getContext().uuidv4();
              scripts.push(regexScript);
            }
          }
          await saveCharRegexScripts(avatar, scripts);
          cfmToastr.success("正则脚本导入成功");
          rerenderCurrentView();
        } catch (err) {
          console.error("[CFM] 正则导入失败:", err);
          cfmToastr.error("导入失败: " + err.message);
        }
      });
      // 新增按钮
      regexToolbar.find(".cfm-regex-create-btn").on("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        createCharScopedRegexFromManager(avatar, charName);
      });
      // 批量操作切换
      regexToolbar.find(".cfm-regex-batch-toggle").on("click", (e) => {
        e.stopPropagation();
        cfmRegexBatchMode = !cfmRegexBatchMode;
        cfmRegexBatchSelected.clear();
        cfmRegexBatchRangeMode = false;
        cfmRegexBatchLastClicked = null;
        rerenderCurrentView();
      });
      subList.append(regexToolbar);

      // === 批量操作工具栏 ===
      if (cfmRegexBatchMode && scripts && scripts.length > 0) {
        const allSel = scripts.every((s) => cfmRegexBatchSelected.has(s.id));
        const selCount = scripts.filter((s) =>
          cfmRegexBatchSelected.has(s.id),
        ).length;
        const batchToolbar = $(`
          <div class="cfm-regex-batch-toolbar">
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-selall" title="全选/全不选">
              <i class="fa-solid fa-${allSel ? "square-minus" : "square-check"}"></i> ${allSel ? "全不选" : "全选"}
            </button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-range ${cfmRegexBatchRangeMode ? "cfm-range-active" : ""}" title="框选模式">
              <i class="fa-solid fa-arrow-down-short-wide"></i> 框选${cfmRegexBatchRangeMode ? "(开)" : ""}
            </button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-activate" title="批量激活"><i class="fa-solid fa-toggle-on"></i> 激活</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-deactivate" title="批量取消激活"><i class="fa-solid fa-toggle-off"></i> 取消激活</button>
            <span class="cfm-regex-batch-count">${selCount > 0 ? `已选 ${selCount} 项` : ""}</span>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-transfer" title="互通正则"><i class="fa-solid fa-right-left"></i> 互通</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-export" title="批量导出"><i class="fa-solid fa-file-export"></i> 导出</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-delete" title="批量删除"><i class="fa-solid fa-trash-can"></i> 删除</button>
          </div>
        `);
        // 全选/全不选
        batchToolbar.find(".cfm-regex-batch-selall").on("click", (e) => {
          e.stopPropagation();
          if (allSel) {
            scripts.forEach((s) => cfmRegexBatchSelected.delete(s.id));
          } else {
            scripts.forEach((s) => {
              if (s.id) cfmRegexBatchSelected.add(s.id);
            });
          }
          rerenderCurrentView();
        });
        // 框选模式
        batchToolbar.find(".cfm-regex-batch-range").on("click", (e) => {
          e.stopPropagation();
          cfmRegexBatchRangeMode = !cfmRegexBatchRangeMode;
          if (cfmRegexBatchRangeMode) cfmRegexBatchLastClicked = null;
          rerenderCurrentView();
        });
        batchToolbar
          .find(".cfm-regex-batch-activate")
          .on("click", async (e) => {
            e.stopPropagation();
            const changed = await applyOwnedRegexBatchActivation({
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
              activate: true,
              save: () => saveCharRegexScripts(avatar, scripts),
            });
            if (changed) rerenderCurrentView();
          });
        batchToolbar
          .find(".cfm-regex-batch-deactivate")
          .on("click", async (e) => {
            e.stopPropagation();
            const changed = await applyOwnedRegexBatchActivation({
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
              activate: false,
              save: () => saveCharRegexScripts(avatar, scripts),
            });
            if (changed) rerenderCurrentView();
          });
        // 互通按钮
        batchToolbar
          .find(".cfm-regex-batch-transfer")
          .on("click", async (e) => {
            e.stopPropagation();
            await startOwnedRegexTransferFlow({
              sourceType: "char",
              sourceName: charName,
              avatar,
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
            });
          });
        // 批量导出（JSON格式，与酒馆保持一致）
        batchToolbar.find(".cfm-regex-batch-export").on("click", async (e) => {
          e.stopPropagation();
          const toExport = scripts.filter((s) =>
            cfmRegexBatchSelected.has(s.id),
          );
          if (toExport.length === 0) {
            cfmToastr.warning("请先选择要导出的正则脚本");
            return;
          }
          try {
            const download = (await import("../../../utils.js")).download;
            if (toExport.length === 1) {
              const fileName = `regex-${(toExport[0].scriptName || "unnamed").replace(/[^\w\-_.]/g, "_")}.json`;
              download(
                JSON.stringify(toExport[0], null, 4),
                fileName,
                "application/json",
              );
            } else {
              const fileName = `regex-${new Date().toISOString()}.json`;
              download(
                JSON.stringify(toExport, null, 4),
                fileName,
                "application/json",
              );
            }
            cfmToastr.success(`已导出 ${toExport.length} 个正则脚本`);
          } catch (err) {
            console.error("[CFM] 批量导出正则失败:", err);
            cfmToastr.error("导出失败: " + err.message);
          }
        });
        // 批量删除
        batchToolbar.find(".cfm-regex-batch-delete").on("click", async (e) => {
          e.stopPropagation();
          const toDeleteIds = scripts
            .filter((s) => cfmRegexBatchSelected.has(s.id))
            .map((s) => s.id);
          if (toDeleteIds.length === 0) {
            cfmToastr.warning("请先选择要删除的正则脚本");
            return;
          }
          if (
            !cfmConfirm(
              `确定要删除选中的 ${toDeleteIds.length} 个正则脚本吗？\n此操作不可撤销！`,
            )
          )
            return;
          try {
            for (const id of toDeleteIds) {
              const idx = scripts.findIndex((s) => s.id === id);
              if (idx !== -1) scripts.splice(idx, 1);
            }
            await saveCharRegexScripts(avatar, scripts);
            cfmRegexBatchSelected.clear();
            cfmToastr.success(`已删除 ${toDeleteIds.length} 个正则脚本`);
            rerenderCurrentView();
          } catch (err) {
            console.error("[CFM] 批量删除正则失败:", err);
            cfmToastr.error("删除失败: " + err.message);
          }
        });
        subList.append(batchToolbar);
      }
    }

    if (!scripts || scripts.length === 0) {
      subList.append(
        '<div class="cfm-right-empty" style="padding:8px 16px;font-size:12px;">该角色没有绑定正则脚本</div>',
      );
    } else {
      for (let i = 0; i < scripts.length; i++) {
        const script = scripts[i];
        const isDisabled = !!script.disabled;
        const isBatchSel =
          isTarget && cfmRegexBatchMode && cfmRegexBatchSelected.has(script.id);
        const toggleHtml = isTarget
          ? `<div class="cfm-wi-toggle ${isDisabled ? "" : "cfm-wi-toggle-on"}" title="${isDisabled ? "已禁用 - 点击启用" : "已启用 - 点击禁用"}"><i class="fa-solid fa-toggle-${isDisabled ? "off" : "on"}"></i></div>`
          : `<div class="cfm-wi-toggle cfm-toggle-readonly ${isDisabled ? "" : "cfm-wi-toggle-on"}" title="${isDisabled ? "已禁用" : "已启用"}（非当前角色，不可切换）"><i class="fa-solid fa-toggle-${isDisabled ? "off" : "on"}"></i></div>`;
        const row = $(`
          <div class="cfm-row cfm-row-char cfm-regex-script-row ${isDisabled ? "cfm-regex-disabled" : ""} ${isBatchSel ? "cfm-regex-batch-selected" : ""}"
               data-script-id="${escapeHtml(script.id || "")}"
               data-script-idx="${i}"
               data-script-type="1"
               data-owner="${escapeHtml(charName || "")}">
            ${isTarget && cfmRegexBatchMode ? `<div class="cfm-regex-batch-check"><i class="fa-${isBatchSel ? "solid" : "regular"} fa-square${isBatchSel ? "-check" : ""}"></i></div>` : ""}
            ${toggleHtml}
            <div class="cfm-row-name">
              <span>${escapeHtml(script.scriptName || "(未命名)")}</span>
            </div>
            <div class="cfm-regex-row-actions">
              <div class="cfm-regex-action-btn cfm-regex-edit-btn" title="编辑"><i class="fa-solid fa-pen-to-square"></i></div>
              ${
                isTarget
                  ? `
              <div class="cfm-regex-action-btn cfm-regex-move-up-btn${i === 0 ? " cfm-regex-move-disabled" : ""}" title="上移"><i class="fa-solid fa-arrow-up"></i></div>
              <div class="cfm-regex-action-btn cfm-regex-move-down-btn${i === scripts.length - 1 ? " cfm-regex-move-disabled" : ""}" title="下移"><i class="fa-solid fa-arrow-down"></i></div>
              `
                  : ""
              }
            </div>
          </div>
        `);

        // 批量模式：行点击切换选中（仅目标角色）
        if (isTarget && cfmRegexBatchMode) {
          row.on("click", (e) => {
            if (
              $(e.target).closest(
                ".cfm-regex-row-actions, .cfm-regex-batch-check",
              ).length
            )
              return;
            toggleRegexBatchItem(script.id, e.shiftKey, scripts);
            rerenderCurrentView();
          });
          row.find(".cfm-regex-batch-check").on("click", (e) => {
            e.stopPropagation();
            toggleRegexBatchItem(script.id, e.shiftKey, scripts);
            rerenderCurrentView();
          });
        }

        // toggle 点击（只有目标角色可操作，readonly的不绑定事件）
        row
          .find(".cfm-wi-toggle:not(.cfm-toggle-readonly)")
          .on("click", async function (e) {
            e.preventDefault();
            e.stopPropagation();
            script.disabled = !script.disabled;
            try {
              await saveCharRegexScripts(avatar, scripts);
            } catch (err) {
              console.error("[CFM] 正则toggle保存失败:", err);
              cfmToastr.error("保存失败: " + err.message);
              script.disabled = !script.disabled;
              return;
            }
            const isNowDisabled = !!script.disabled;
            const el = $(this);
            el.toggleClass("cfm-wi-toggle-on", !isNowDisabled);
            el.find("i").attr(
              "class",
              `fa-solid fa-toggle-${isNowDisabled ? "off" : "on"}`,
            );
            el.attr(
              "title",
              isNowDisabled ? "已禁用 - 点击启用" : "已启用 - 点击禁用",
            );
            row.toggleClass("cfm-regex-disabled", isNowDisabled);
          });
        // 编辑按钮点击
        row.find(".cfm-regex-edit-btn").on("click", function (e) {
          e.preventDefault();
          e.stopPropagation();
          const scriptId = row.data("script-id");
          if (!scriptId) return;
          const nativeEl = $("#" + $.escapeSelector(String(scriptId)));
          if (nativeEl.length) {
            nativeEl.find(".edit_existing_regex").trigger("click");
          } else {
            cfmToastr.warning("非当前角色的正则脚本，无法编辑");
          }
        });
        // 上移按钮
        row.find(".cfm-regex-move-up-btn").on("click", async function (e) {
          e.preventDefault();
          e.stopPropagation();
          if (i <= 0) return;
          const movedScriptId = String(script?.id || "").trim();
          [scripts[i - 1], scripts[i]] = [scripts[i], scripts[i - 1]];
          try {
            await saveCharRegexScripts(avatar, scripts);
            rerenderCurrentView();
            if (movedScriptId) {
              flashDraggedElement(
                `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
              );
            }
          } catch (err) {
            console.error("[CFM] 正则上移失败:", err);
            [scripts[i - 1], scripts[i]] = [scripts[i], scripts[i - 1]];
            cfmToastr.error("上移失败: " + err.message);
          }
        });
        // 下移按钮
        row.find(".cfm-regex-move-down-btn").on("click", async function (e) {
          e.preventDefault();
          e.stopPropagation();
          if (i >= scripts.length - 1) return;
          const movedScriptId = String(script?.id || "").trim();
          [scripts[i], scripts[i + 1]] = [scripts[i + 1], scripts[i]];
          try {
            await saveCharRegexScripts(avatar, scripts);
            rerenderCurrentView();
            if (movedScriptId) {
              flashDraggedElement(
                `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
              );
            }
          } catch (err) {
            console.error("[CFM] 正则下移失败:", err);
            [scripts[i], scripts[i + 1]] = [scripts[i + 1], scripts[i]];
            cfmToastr.error("下移失败: " + err.message);
          }
        });
        subList.append(row);
      }

      // 拖拽排序（仅目标角色）
      if (
        isTarget &&
        typeof subList.sortable === "function" &&
        !cfmIsTouchDevice()
      ) {
        subList.sortable({
          items: ".cfm-regex-script-row",
          axis: "y",
          tolerance: "pointer",
          placeholder: "cfm-sort-placeholder",
          forcePlaceholderSize: true,
          distance: 4,
          cancel:
            ".cfm-chat-actions, .cfm-regex-batch-check, .cfm-wi-toggle, .cfm-regex-edit-btn, .cfm-regex-move-up-btn, .cfm-regex-move-down-btn, button, input, textarea, select, a, label",
          start: (_event, ui) => {
            ui.item.addClass("cfm-regex-dragging");
          },
          stop: async (_event, ui) => {
            const movedScriptId = String(
              ui.item.data("script-id") || "",
            ).trim();
            ui.item.removeClass("cfm-regex-dragging");
            const orderedIds = subList
              .find(".cfm-regex-script-row")
              .map(function () {
                return String($(this).data("script-id") || "").trim();
              })
              .get()
              .filter(Boolean);
            const currentIds = scripts
              .map((script) => String(script?.id || "").trim())
              .filter(Boolean);
            if (
              orderedIds.length !== currentIds.length ||
              orderedIds.every((id, index) => id === currentIds[index])
            ) {
              return;
            }
            const scriptMap = new Map(
              scripts
                .map((script) => [String(script?.id || "").trim(), script])
                .filter(([id]) => !!id),
            );
            const reorderedScripts = orderedIds
              .map((id) => scriptMap.get(id))
              .filter(Boolean);
            try {
              await saveCharRegexScripts(avatar, reorderedScripts);
              rerenderCurrentView();
              if (movedScriptId) {
                flashDraggedElement(
                  `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
                );
              }
            } catch (err) {
              console.error("[CFM] 正则拖拽排序失败:", err);
              cfmToastr.error("排序失败: " + err.message);
              rerenderCurrentView();
            }
          },
        });
        subList.disableSelection();
      }
    }
    charRow.after(subList);
  }

  /**
   * 正则批量选择切换（支持框选/Shift多选）
   * @param {string} scriptId - 脚本ID
   * @param {boolean} shiftKey - 是否按住了 Shift 键
   * @param {Array} scripts - 当前脚本列表
   */
  function toggleRegexBatchItem(scriptId, shiftKey, scripts) {
    if ((shiftKey || cfmRegexBatchRangeMode) && cfmRegexBatchLastClicked) {
      // 框选：从上次点击到当前点击的范围
      const ids = scripts.map((s) => s.id);
      const lastIdx = ids.indexOf(cfmRegexBatchLastClicked);
      const curIdx = ids.indexOf(scriptId);
      if (lastIdx !== -1 && curIdx !== -1) {
        const start = Math.min(lastIdx, curIdx);
        const end = Math.max(lastIdx, curIdx);
        for (let i = start; i <= end; i++) {
          if (ids[i]) cfmRegexBatchSelected.add(ids[i]);
        }
      }
    } else {
      if (cfmRegexBatchSelected.has(scriptId)) {
        cfmRegexBatchSelected.delete(scriptId);
      } else {
        cfmRegexBatchSelected.add(scriptId);
      }
    }
    cfmRegexBatchLastClicked = scriptId;
  }

  async function applyOwnedRegexBatchActivation({
    scripts,
    selectedIds,
    activate,
    save,
    successLabel = "正则脚本",
  }) {
    const normalizedIds = Array.from(
      new Set(
        (Array.isArray(selectedIds) ? selectedIds : [])
          .map((id) => String(id || ""))
          .filter(Boolean),
      ),
    );
    if (!normalizedIds.length) {
      cfmToastr.warning("请先选择要操作的正则脚本");
      return false;
    }
    if (!Array.isArray(scripts) || typeof save !== "function") {
      cfmToastr.error("批量激活正则脚本失败：缺少保存上下文");
      return false;
    }

    const touched = [];
    let changedCount = 0;
    for (const scriptId of normalizedIds) {
      const script = scripts.find((item) => item?.id === scriptId);
      if (!script) continue;
      const oldDisabled = !!script.disabled;
      const nextDisabled = !activate;
      if (oldDisabled === nextDisabled) continue;
      touched.push([script, oldDisabled]);
      script.disabled = nextDisabled;
      changedCount++;
    }

    if (!changedCount) {
      cfmToastr.warning("所选正则脚本状态未发生变化");
      return false;
    }

    try {
      await save();
      cfmToastr.success(
        `已${activate ? "激活" : "取消激活"} ${changedCount} 个${successLabel}`,
      );
      return true;
    } catch (error) {
      for (const [script, oldDisabled] of touched) {
        script.disabled = oldDisabled;
      }
      console.error("[CFM] 批量切换正则脚本激活状态失败:", error);
      cfmToastr.error(`保存失败: ${error.message || error}`);
      return false;
    }
  }

  async function applyWorldInfoMultiActivation(bookNames, activate) {
    const normalizedNames = Array.from(
      new Set(
        (Array.isArray(bookNames) ? bookNames : [])
          .map((name) => String(name || ""))
          .filter(Boolean),
      ),
    );
    if (!normalizedNames.length) {
      cfmToastr.warning("请先选择要操作的世界书");
      return false;
    }

    const charBound = await getCharBoundWorldBooks();
    const activeSet = await getActiveWorldInfoSet();
    let changedCount = 0;
    let skippedCount = 0;

    for (const name of normalizedNames) {
      if (charBound.has(name)) {
        skippedCount++;
        continue;
      }
      if (activeSet.has(name) === activate) continue;
      await toggleWorldInfoActivation(name, activate);
      if (activate) activeSet.add(name);
      else activeSet.delete(name);
      syncWiPresetTrackingForManualToggle(name, activate);
      changedCount++;
    }

    if (changedCount > 0) {
      cfmToastr.success(
        `已${activate ? "激活" : "取消激活"} ${changedCount} 个世界书`,
      );
    } else {
      cfmToastr.warning(
        `所选世界书状态未发生变化${skippedCount ? "（角色关联项已自动跳过）" : ""}`,
      );
    }
    if (skippedCount > 0) {
      cfmToastr.info(`已跳过 ${skippedCount} 个角色关联世界书`);
    }
    return changedCount > 0;
  }

  async function applyQrMultiActivation(setNames, activate) {
    const normalizedNames = Array.from(
      new Set(
        (Array.isArray(setNames) ? setNames : [])
          .map((name) => String(name || "").trim())
          .filter(Boolean),
      ),
    );
    if (!normalizedNames.length) {
      cfmToastr.warning("请先选择要操作的快速回复集");
      return false;
    }

    const existingNameSet = getExistingQrSetNameSet();
    const validNames = normalizedNames.filter((name) =>
      existingNameSet.has(name),
    );
    if (!validNames.length) {
      cfmToastr.warning("所选快速回复集已不存在");
      return false;
    }

    const activeSet = getActiveQrSets();
    let changedCount = 0;
    for (const name of validNames) {
      if (activeSet.has(name) === activate) continue;
      const changed = await toggleQrSetActivation(name, activate);
      if (!changed) continue;
      if (activate) activeSet.add(name);
      else activeSet.delete(name);
      syncQrPresetTrackingForManualToggle(name, activate);
      changedCount++;
    }

    if (!changedCount) {
      cfmToastr.warning("所选快速回复集状态未发生变化");
      return false;
    }

    cfmToastr.success(
      `已${activate ? "激活" : "取消激活"} ${changedCount} 个快速回复集`,
    );
    return true;
  }

  async function applyGlobalRegexMultiActivation(scriptIds, activate) {
    const normalizedIds = Array.from(
      new Set(
        (Array.isArray(scriptIds) ? scriptIds : [])
          .map((id) => String(id || ""))
          .filter(Boolean),
      ),
    );
    if (!normalizedIds.length) {
      cfmToastr.warning("请先选择要操作的正则脚本");
      return false;
    }

    const globalScripts = extension_settings.regex ?? [];
    const touched = [];
    let changedCount = 0;
    for (const scriptId of normalizedIds) {
      const script = globalScripts.find((item) => item?.id === scriptId);
      if (!script) continue;
      const oldDisabled = !!script.disabled;
      const nextDisabled = !activate;
      if (oldDisabled === nextDisabled) continue;
      touched.push([script, oldDisabled]);
      toggleRegexScriptActivation(scriptId, activate);
      changedCount++;
    }

    if (!changedCount) {
      cfmToastr.warning("所选正则脚本状态未发生变化");
      return false;
    }

    try {
      getContext().saveSettingsDebounced();
      await syncNativeRegexState();
      cfmToastr.success(
        `已${activate ? "激活" : "取消激活"} ${changedCount} 个正则脚本`,
      );
      return true;
    } catch (error) {
      for (const [script, oldDisabled] of touched) {
        script.disabled = oldDisabled;
      }
      console.error("[CFM] 批量切换全局正则激活状态失败:", error);
      cfmToastr.error(`保存失败: ${error.message || error}`);
      return false;
    }
  }

  /**
   * 保存预设正则脚本
   * @param {Array} scripts - 正则脚本列表
   */
  async function savePresetRegexScripts(scripts) {
    const pm = getContext().getPresetManager();
    if (pm) {
      await pm.writePresetExtensionField({
        path: "regex_scripts",
        value: scripts,
      });
    }
    // 清除原生正则引擎缓存 & 刷新原生正则UI
    await syncNativeRegexState();
  }

  /**
   * 渲染预设的正则脚本子列表
   * @param {jQuery} presetRow - 预设行的 jQuery 对象
   * @param {string} presetName - 预设名称
   * @param {Array} scripts - 正则脚本列表
   * @param {boolean} [isTarget=true] - 是否为当前目标预设（只有目标预设可激活/取消激活正则）
   */
  function renderPresetRegexSubList(
    presetRow,
    presetName,
    scripts,
    isTarget = true,
  ) {
    presetRow.next(".cfm-regex-sublist").remove();
    const subList = $('<div class="cfm-regex-sublist"></div>');

    // === 工具栏（仅对目标预设显示） ===
    if (isTarget) {
      const regexToolbar = $(`
        <div class="cfm-regex-toolbar">
          <button class="cfm-btn cfm-btn-sm cfm-regex-import-btn" title="导入正则脚本"><i class="fa-solid fa-file-import"></i> 导入</button>
          <input type="file" class="cfm-regex-import-file" multiple accept=".json" style="display:none;">
          <button class="cfm-btn cfm-btn-sm cfm-regex-create-btn" title="新增正则脚本"><i class="fa-solid fa-plus"></i> 新增</button>
          <button class="cfm-btn cfm-btn-sm cfm-regex-batch-toggle ${cfmRegexBatchMode ? "cfm-regex-batch-active" : ""}" title="批量操作模式"><i class="fa-solid fa-list-check"></i> ${cfmRegexBatchMode ? "退出批量" : "批量操作"}</button>
          <span class="cfm-regex-count">${scripts ? scripts.length : 0} 个脚本</span>
        </div>
      `);
      // 导入按钮
      regexToolbar.find(".cfm-regex-import-btn").on("click", (e) => {
        e.stopPropagation();
        regexToolbar.find(".cfm-regex-import-file").val("").trigger("click");
      });
      regexToolbar.find(".cfm-regex-import-file").on("change", async (e) => {
        e.stopPropagation();
        const files = e.target.files;
        if (!files || files.length === 0) return;
        try {
          for (const file of files) {
            const text = await file.text();
            const parsed = JSON.parse(text);
            const toImport = Array.isArray(parsed) ? parsed : [parsed];
            for (const regexScript of toImport) {
              if (!regexScript.scriptName) {
                cfmToastr.warning("跳过无名称的正则脚本");
                continue;
              }
              regexScript.id = getContext().uuidv4();
              scripts.push(regexScript);
            }
          }
          await savePresetRegexScripts(scripts);
          cfmToastr.success("正则脚本导入成功");
          rerenderCurrentView();
        } catch (err) {
          console.error("[CFM] 正则导入失败:", err);
          cfmToastr.error("导入失败: " + err.message);
        }
      });
      // 新增按钮
      regexToolbar.find(".cfm-regex-create-btn").on("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        createPresetRegexFromManager(presetName);
      });
      // 批量操作切换
      regexToolbar.find(".cfm-regex-batch-toggle").on("click", (e) => {
        e.stopPropagation();
        cfmRegexBatchMode = !cfmRegexBatchMode;
        cfmRegexBatchSelected.clear();
        cfmRegexBatchRangeMode = false;
        cfmRegexBatchLastClicked = null;
        rerenderCurrentView();
      });
      subList.append(regexToolbar);

      // === 批量操作工具栏 ===
      if (cfmRegexBatchMode && scripts && scripts.length > 0) {
        const allSel = scripts.every((s) => cfmRegexBatchSelected.has(s.id));
        const selCount = scripts.filter((s) =>
          cfmRegexBatchSelected.has(s.id),
        ).length;
        const batchToolbar = $(`
          <div class="cfm-regex-batch-toolbar">
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-selall" title="全选/全不选">
              <i class="fa-solid fa-${allSel ? "square-minus" : "square-check"}"></i> ${allSel ? "全不选" : "全选"}
            </button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-range ${cfmRegexBatchRangeMode ? "cfm-range-active" : ""}" title="框选模式">
              <i class="fa-solid fa-arrow-down-short-wide"></i> 框选${cfmRegexBatchRangeMode ? "(开)" : ""}
            </button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-activate" title="批量激活"><i class="fa-solid fa-toggle-on"></i> 激活</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-deactivate" title="批量取消激活"><i class="fa-solid fa-toggle-off"></i> 取消激活</button>
            <span class="cfm-regex-batch-count">${selCount > 0 ? `已选 ${selCount} 项` : ""}</span>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-transfer" title="互通正则"><i class="fa-solid fa-right-left"></i> 互通</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-export" title="批量导出"><i class="fa-solid fa-file-export"></i> 导出</button>
            <button class="cfm-btn cfm-btn-sm cfm-regex-batch-delete" title="批量删除"><i class="fa-solid fa-trash-can"></i> 删除</button>
          </div>
        `);
        // 全选/全不选
        batchToolbar.find(".cfm-regex-batch-selall").on("click", (e) => {
          e.stopPropagation();
          if (allSel) {
            scripts.forEach((s) => cfmRegexBatchSelected.delete(s.id));
          } else {
            scripts.forEach((s) => {
              if (s.id) cfmRegexBatchSelected.add(s.id);
            });
          }
          rerenderCurrentView();
        });
        // 框选模式
        batchToolbar.find(".cfm-regex-batch-range").on("click", (e) => {
          e.stopPropagation();
          cfmRegexBatchRangeMode = !cfmRegexBatchRangeMode;
          if (cfmRegexBatchRangeMode) cfmRegexBatchLastClicked = null;
          rerenderCurrentView();
        });
        batchToolbar
          .find(".cfm-regex-batch-activate")
          .on("click", async (e) => {
            e.stopPropagation();
            const changed = await applyOwnedRegexBatchActivation({
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
              activate: true,
              save: () => savePresetRegexScripts(scripts),
            });
            if (changed) rerenderCurrentView();
          });
        batchToolbar
          .find(".cfm-regex-batch-deactivate")
          .on("click", async (e) => {
            e.stopPropagation();
            const changed = await applyOwnedRegexBatchActivation({
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
              activate: false,
              save: () => savePresetRegexScripts(scripts),
            });
            if (changed) rerenderCurrentView();
          });
        // 互通按钮
        batchToolbar
          .find(".cfm-regex-batch-transfer")
          .on("click", async (e) => {
            e.stopPropagation();
            await startOwnedRegexTransferFlow({
              sourceType: "preset",
              sourceName: presetName,
              scripts,
              selectedIds: Array.from(cfmRegexBatchSelected),
            });
          });
        // 批量导出（JSON格式，与酒馆保持一致）
        batchToolbar.find(".cfm-regex-batch-export").on("click", async (e) => {
          e.stopPropagation();
          const toExport = scripts.filter((s) =>
            cfmRegexBatchSelected.has(s.id),
          );
          if (toExport.length === 0) {
            cfmToastr.warning("请先选择要导出的正则脚本");
            return;
          }
          try {
            const download = (await import("../../../utils.js")).download;
            if (toExport.length === 1) {
              const fileName = `regex-${(toExport[0].scriptName || "unnamed").replace(/[^\w\-_.]/g, "_")}.json`;
              download(
                JSON.stringify(toExport[0], null, 4),
                fileName,
                "application/json",
              );
            } else {
              const fileName = `regex-${new Date().toISOString()}.json`;
              download(
                JSON.stringify(toExport, null, 4),
                fileName,
                "application/json",
              );
            }
            cfmToastr.success(`已导出 ${toExport.length} 个正则脚本`);
          } catch (err) {
            console.error("[CFM] 批量导出正则失败:", err);
            cfmToastr.error("导出失败: " + err.message);
          }
        });
        // 批量删除
        batchToolbar.find(".cfm-regex-batch-delete").on("click", async (e) => {
          e.stopPropagation();
          const toDeleteIds = scripts
            .filter((s) => cfmRegexBatchSelected.has(s.id))
            .map((s) => s.id);
          if (toDeleteIds.length === 0) {
            cfmToastr.warning("请先选择要删除的正则脚本");
            return;
          }
          if (
            !cfmConfirm(
              `确定要删除选中的 ${toDeleteIds.length} 个正则脚本吗？\n此操作不可撤销！`,
            )
          )
            return;
          try {
            for (const id of toDeleteIds) {
              const idx = scripts.findIndex((s) => s.id === id);
              if (idx !== -1) scripts.splice(idx, 1);
            }
            await savePresetRegexScripts(scripts);
            cfmRegexBatchSelected.clear();
            cfmToastr.success(`已删除 ${toDeleteIds.length} 个正则脚本`);
            rerenderCurrentView();
          } catch (err) {
            console.error("[CFM] 批量删除正则失败:", err);
            cfmToastr.error("删除失败: " + err.message);
          }
        });
        subList.append(batchToolbar);
      }
    }

    if (!scripts || scripts.length === 0) {
      subList.append(
        '<div class="cfm-right-empty" style="padding:8px 16px;font-size:12px;">该预设没有绑定正则脚本</div>',
      );
    } else {
      for (let i = 0; i < scripts.length; i++) {
        const script = scripts[i];
        const isDisabled = !!script.disabled;
        const isBatchSel =
          isTarget && cfmRegexBatchMode && cfmRegexBatchSelected.has(script.id);
        const toggleHtml = isTarget
          ? `<div class="cfm-wi-toggle ${isDisabled ? "" : "cfm-wi-toggle-on"}" title="${isDisabled ? "已禁用 - 点击启用" : "已启用 - 点击禁用"}"><i class="fa-solid fa-toggle-${isDisabled ? "off" : "on"}"></i></div>`
          : `<div class="cfm-wi-toggle cfm-toggle-readonly ${isDisabled ? "" : "cfm-wi-toggle-on"}" title="${isDisabled ? "已禁用" : "已启用"}（非当前预设，不可切换）"><i class="fa-solid fa-toggle-${isDisabled ? "off" : "on"}"></i></div>`;
        const row = $(`
          <div class="cfm-row cfm-row-char cfm-regex-script-row ${isDisabled ? "cfm-regex-disabled" : ""} ${isBatchSel ? "cfm-regex-batch-selected" : ""}"
               data-script-id="${escapeHtml(script.id || "")}"
               data-script-idx="${i}"
               data-script-type="2"
               data-owner="${escapeHtml(presetName || "")}">
            ${isTarget && cfmRegexBatchMode ? `<div class="cfm-regex-batch-check"><i class="fa-${isBatchSel ? "solid" : "regular"} fa-square${isBatchSel ? "-check" : ""}"></i></div>` : ""}
            ${toggleHtml}
            <div class="cfm-row-name">
              <span>${escapeHtml(script.scriptName || "(未命名)")}</span>
            </div>
            <div class="cfm-regex-row-actions">
              <div class="cfm-regex-action-btn cfm-regex-edit-btn" title="编辑"><i class="fa-solid fa-pen-to-square"></i></div>
              ${
                isTarget
                  ? `
              <div class="cfm-regex-action-btn cfm-regex-move-up-btn${i === 0 ? " cfm-regex-move-disabled" : ""}" title="上移"><i class="fa-solid fa-arrow-up"></i></div>
              <div class="cfm-regex-action-btn cfm-regex-move-down-btn${i === scripts.length - 1 ? " cfm-regex-move-disabled" : ""}" title="下移"><i class="fa-solid fa-arrow-down"></i></div>
              `
                  : ""
              }
            </div>
          </div>
        `);

        // 批量模式：行点击切换选中（仅目标预设）
        if (isTarget && cfmRegexBatchMode) {
          row.on("click", (e) => {
            if (
              $(e.target).closest(
                ".cfm-regex-row-actions, .cfm-regex-batch-check",
              ).length
            )
              return;
            toggleRegexBatchItem(script.id, e.shiftKey, scripts);
            rerenderCurrentView();
          });
          row.find(".cfm-regex-batch-check").on("click", (e) => {
            e.stopPropagation();
            toggleRegexBatchItem(script.id, e.shiftKey, scripts);
            rerenderCurrentView();
          });
        }

        // toggle 点击（只有目标预设可操作，readonly的不绑定事件）
        row
          .find(".cfm-wi-toggle:not(.cfm-toggle-readonly)")
          .on("click", async function (e) {
            e.preventDefault();
            e.stopPropagation();
            script.disabled = !script.disabled;
            try {
              await savePresetRegexScripts(scripts);
            } catch (err) {
              console.error("[CFM] 正则toggle保存失败:", err);
              cfmToastr.error("保存失败: " + err.message);
              script.disabled = !script.disabled;
              return;
            }
            const isNowDisabled = !!script.disabled;
            const el = $(this);
            el.toggleClass("cfm-wi-toggle-on", !isNowDisabled);
            el.find("i").attr(
              "class",
              `fa-solid fa-toggle-${isNowDisabled ? "off" : "on"}`,
            );
            el.attr(
              "title",
              isNowDisabled ? "已禁用 - 点击启用" : "已启用 - 点击禁用",
            );
            row.toggleClass("cfm-regex-disabled", isNowDisabled);
          });
        // 编辑按钮点击
        row.find(".cfm-regex-edit-btn").on("click", function (e) {
          e.preventDefault();
          e.stopPropagation();
          const scriptId = row.data("script-id");
          if (!scriptId) return;
          const nativeEl = $("#" + $.escapeSelector(String(scriptId)));
          if (nativeEl.length) {
            nativeEl.find(".edit_existing_regex").trigger("click");
          } else {
            cfmToastr.warning("非当前预设的正则脚本，无法编辑");
          }
        });
        // 上移按钮
        row.find(".cfm-regex-move-up-btn").on("click", async function (e) {
          e.preventDefault();
          e.stopPropagation();
          if (i <= 0) return;
          const movedScriptId = String(script?.id || "").trim();
          [scripts[i - 1], scripts[i]] = [scripts[i], scripts[i - 1]];
          try {
            await savePresetRegexScripts(scripts);
            rerenderCurrentView();
            if (movedScriptId) {
              flashDraggedElement(
                `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
              );
            }
          } catch (err) {
            console.error("[CFM] 正则上移失败:", err);
            [scripts[i - 1], scripts[i]] = [scripts[i], scripts[i - 1]];
            cfmToastr.error("上移失败: " + err.message);
          }
        });
        // 下移按钮
        row.find(".cfm-regex-move-down-btn").on("click", async function (e) {
          e.preventDefault();
          e.stopPropagation();
          if (i >= scripts.length - 1) return;
          const movedScriptId = String(script?.id || "").trim();
          [scripts[i], scripts[i + 1]] = [scripts[i + 1], scripts[i]];
          try {
            await savePresetRegexScripts(scripts);
            rerenderCurrentView();
            if (movedScriptId) {
              flashDraggedElement(
                `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
              );
            }
          } catch (err) {
            console.error("[CFM] 正则下移失败:", err);
            [scripts[i], scripts[i + 1]] = [scripts[i + 1], scripts[i]];
            cfmToastr.error("下移失败: " + err.message);
          }
        });
        subList.append(row);
      }

      // 拖拽排序（仅目标预设）
      if (
        isTarget &&
        typeof subList.sortable === "function" &&
        !cfmIsTouchDevice()
      ) {
        subList.sortable({
          items: ".cfm-regex-script-row",
          axis: "y",
          tolerance: "pointer",
          placeholder: "cfm-sort-placeholder",
          forcePlaceholderSize: true,
          distance: 4,
          cancel:
            ".cfm-chat-actions, .cfm-regex-batch-check, .cfm-wi-toggle, .cfm-regex-edit-btn, .cfm-regex-move-up-btn, .cfm-regex-move-down-btn, button, input, textarea, select, a, label",
          start: (_event, ui) => {
            ui.item.addClass("cfm-regex-dragging");
          },
          stop: async (_event, ui) => {
            const movedScriptId = String(
              ui.item.data("script-id") || "",
            ).trim();
            ui.item.removeClass("cfm-regex-dragging");
            const orderedIds = subList
              .find(".cfm-regex-script-row")
              .map(function () {
                return String($(this).data("script-id") || "").trim();
              })
              .get()
              .filter(Boolean);
            const currentIds = scripts
              .map((script) => String(script?.id || "").trim())
              .filter(Boolean);
            if (
              orderedIds.length !== currentIds.length ||
              orderedIds.every((id, index) => id === currentIds[index])
            ) {
              return;
            }
            const scriptMap = new Map(
              scripts
                .map((script) => [String(script?.id || "").trim(), script])
                .filter(([id]) => !!id),
            );
            const reorderedScripts = orderedIds
              .map((id) => scriptMap.get(id))
              .filter(Boolean);
            try {
              await savePresetRegexScripts(reorderedScripts);
              rerenderCurrentView();
              if (movedScriptId) {
                flashDraggedElement(
                  `.cfm-regex-script-row[data-script-id="${$.escapeSelector(movedScriptId)}"]`,
                );
              }
            } catch (err) {
              console.error("[CFM] 正则拖拽排序失败:", err);
              cfmToastr.error("排序失败: " + err.message);
              rerenderCurrentView();
            }
          },
        });
        subList.disableSelection();
      }
    }
    presetRow.after(subList);
  }

  /**
   * 获取角色的聊天记录列表（带缓存）
   * @param {string} avatar - 角色的 avatar 文件名
   * @returns {Promise<Array>} 聊天记录列表
   */
  async function getCharChats(avatar) {
    if (cfmChatCache.has(avatar)) return cfmChatCache.get(avatar);
    const characters = getCharacters();
    const charIdx = characters.findIndex((c) => c.avatar === avatar);
    if (charIdx < 0) {
      cfmChatCache.set(avatar, []);
      return [];
    }
    if (!getPastCharacterChatsFunc) {
      // 回退：通过 getContext 获取
      const ctx = getContext();
      if (ctx.getRequestHeaders) {
        try {
          const response = await fetch("/api/characters/chats", {
            method: "POST",
            body: JSON.stringify({ avatar_url: avatar }),
            headers: ctx.getRequestHeaders(),
          });
          if (!response.ok) {
            cfmChatCache.set(avatar, []);
            return [];
          }
          const data = await response.json();
          if (typeof data === "object" && data.error === true) {
            cfmChatCache.set(avatar, []);
            return [];
          }
          const chats = Object.values(data)
            .sort((a, b) => a["file_name"].localeCompare(b["file_name"]))
            .reverse();
          cfmChatCache.set(avatar, chats);
          return chats;
        } catch (e) {
          console.error("[CFM] 获取聊天记录失败:", e);
          cfmChatCache.set(avatar, []);
          return [];
        }
      }
      cfmChatCache.set(avatar, []);
      return [];
    }
    try {
      const chats = await getPastCharacterChatsFunc(charIdx);
      cfmChatCache.set(avatar, chats);
      return chats;
    } catch (e) {
      console.error("[CFM] 获取聊天记录失败:", e);
      cfmChatCache.set(avatar, []);
      return [];
    }
  }

  /**
   * 使某个角色的聊天缓存失效
   */
  async function invalidateChatCache(avatar) {
    cfmChatCache.delete(avatar);
    // 立即重新加载缓存，避免后续 rerenderCurrentView 时三角箭头消失
    await getCharChats(avatar);
  }

  /**
   * 正则脚本重命名弹窗（cfm-edit-popup 风格）
   * @param {string} currentName - 当前脚本名称
   * @returns {Promise<string|null>} 新名称或 null（取消时）
   */
  function showRegexRenamePopup(currentName) {
    return new Promise((resolve) => {
      const popupHtml = `
        <div class="cfm-edit-popup-overlay">
          <div class="cfm-edit-popup">
            <div class="cfm-edit-popup-title">重命名正则脚本</div>
            <div class="cfm-edit-popup-names"><span class="cfm-edit-popup-name-tag">${escapeHtml(currentName)}</span></div>
            <div class="cfm-edit-popup-field">
              <label>新名称</label>
              <input type="text" class="cfm-edit-input" id="cfm-regex-rename-input" value="${escapeHtml(currentName)}" placeholder="输入新名称">
            </div>
            <div class="cfm-edit-popup-actions">
              <button class="cfm-btn cfm-edit-popup-cancel">取消</button>
              <button class="cfm-btn cfm-edit-popup-confirm">确认</button>
            </div>
          </div>
        </div>`;
      const overlay = $(popupHtml);
      $("body").append(overlay);
      overlay.find("#cfm-regex-rename-input").trigger("focus").select();
      overlay.find(".cfm-edit-popup-cancel").on("click", () => {
        overlay.remove();
        resolve(null);
      });
      overlay.find(".cfm-edit-popup-overlay").on("click", (e) => {
        if ($(e.target).hasClass("cfm-edit-popup-overlay")) {
          overlay.remove();
          resolve(null);
        }
      });
      overlay.find(".cfm-edit-popup-confirm").on("click", () => {
        const newName = overlay.find("#cfm-regex-rename-input").val().trim();
        overlay.remove();
        resolve(newName || null);
      });
      overlay.find("#cfm-regex-rename-input").on("keydown", (e) => {
        if (e.key === "Enter") {
          e.preventDefault();
          overlay.find(".cfm-edit-popup-confirm").trigger("click");
        }
        if (e.key === "Escape") {
          overlay.find(".cfm-edit-popup-cancel").trigger("click");
        }
      });
    });
  }

